import json
import pymysql
import os
from typing import Dict, Any, List

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Database connection parameters from environment variables
    db_config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME'],
        'port': int(os.environ.get('DB_PORT', 3306)),
        'connect_timeout': 5,
        'read_timeout': 5,
        'write_timeout': 5
    }
    
    # Initialize connection and cursor
    connection = None
    cursor = None
    
    try:
        # Establish database connection
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Parse query parameters from API Gateway event
        query_params = event.get('queryStringParameters', {})
        if not query_params:
            query_params = {}
        
        # Build dynamic SQL query
        sql_conditions = []
        sql_values = []
        
        # Handle search term
        search_term = query_params.get('search')
        if search_term:
            sql_conditions.append("(name LIKE %s OR description LIKE %s)")
            sql_values.extend([f"%{search_term}%", f"%{search_term}%"])
        
        # Handle category filter
        category = query_params.get('category')
        if category:
            sql_conditions.append("category = %s")
            sql_values.append(category)
        
        # Handle price range
        min_price = query_params.get('min_price')
        max_price = query_params.get('max_price')
        if min_price is not None:
            sql_conditions.append("price >= %s")
            sql_values.append(float(min_price))
        if max_price is not None:
            sql_conditions.append("price <= %s")
            sql_values.append(float(max_price))
        
        # Handle sort parameters
        sort_by = query_params.get('sort_by', 'name')
        sort_order = query_params.get('sort_order', 'ASC')
        
        # Validate sort parameters to prevent SQL injection
        allowed_sort_fields = ['name', 'price', 'category', 'created_at']
        if sort_by not in allowed_sort_fields:
            sort_by = 'name'
        
        allowed_sort_orders = ['ASC', 'DESC']
        if sort_order not in allowed_sort_orders:
            sort_order = 'ASC'
        
        # Build base query
        base_query = "SELECT * FROM products"
        
        # Add WHERE clause if conditions exist
        if sql_conditions:
            where_clause = " AND ".join(sql_conditions)
            base_query += f" WHERE {where_clause}"
        
        # Add ORDER BY clause
        base_query += f" ORDER BY {sort_by} {sort_order}"
        
        # Add LIMIT clause with validation
        limit = query_params.get('limit', '10')
        try:
            limit = int(limit)
            if limit <= 0:
                limit = 10
            elif limit > 100:
                limit = 100
        except (ValueError, TypeError):
            limit = 10
            
        offset = query_params.get('offset', '0')
        try:
            offset = int(offset)
            if offset < 0:
                offset = 0
        except (ValueError, TypeError):
            offset = 0
            
        base_query += f" LIMIT {limit} OFFSET {offset}"
        
        # Execute query
        cursor.execute(base_query, sql_values)
        results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'count': len(results)
            })
        }
        
    except Exception as e:
        # Log error for debugging (in production, use proper logging)
        print(f"Database error: {str(e)}")
        
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': 'Internal server error'
            })
        }
        
    finally:
        # Clean up database connections
        if cursor:
            cursor.close()
        if connection:
            connection.close()